# load all missing korean keys
keys = []
with open("_all_missing.txt", encoding="utf-8") as f:
    for line in f:
        line = line.rstrip("\n")
        if " :: " not in line: continue
        keys.append(line.split(" :: ")[0])

batch = {}
skipped = []
for sub, trans in items:
    matches = [k for k in keys if sub in k]
    if len(matches) != 1:
        skipped.append((sub, len(matches)))
        continue
    key = matches[0]
    batch[key] = {LANGS[i]: trans[i] for i in range(len(LANGS))}

with open("_batch.json", "w", encoding="utf-8") as f:
    json.dump(batch, f, ensure_ascii=False, indent=1)

print("built:", len(batch), "items")
for s,n in skipped:
    print("SKIPPED (matches=%d):"%n, s)
